    .aplus-v2 .aplus-standard tr.apm-tablemodule-keyvalue td {padding-top8px !important; padding-left14px; padding-bottom8px; border-top1px solid #dddddd; border-bottom1px solid #dddddd; text-aligncenter;widthinherit!important}
    .aplus-v2 .aplus-standard .apm-tablemodule-valuecell { vertical-align middle }
